7	class WhoILikeScreen extends StatefulWidget {
8	  final Function(int) onSwitchTab;
9	
10	  const WhoILikeScreen({super.key, required this.onSwitchTab});
11	
12	  @override
13	  State<WhoILikeScreen> createState() => _WhoILikeScreenState();
14	}
15	
16	class _WhoILikeScreenState extends State<WhoILikeScreen> {
17	  static const _bg = Color(0xFF0E0E0E);
18	  static const _surface = Color(0xFF1A1A1A);
19	  static const _baseUrl = 'http://10.0.2.2:8000';
20	
21	  bool _isLoading = true;
22	  String? _error;
23	  List<Map<String, dynamic>> _likes = [];
24	
25	  // Unique colour per rank — cycles after 12
26	  static const _rankColors = [
27	    Color(0xFFFFC107), //  1 - amber
28	    Color(0xFFFF5722), //  2 - deep orange
29	    Color(0xFFE91E8C), //  3 - pink
30	    Color(0xFF00BCD4), //  4 - cyan
31	    Color(0xFF8BC34A), //  5 - light green
32	    Color(0xFF9C27B0), //  6 - purple
33	    Color(0xFF03A9F4), //  7 - light blue
34	    Color(0xFFFF9800), //  8 - orange
35	    Color(0xFF4CAF50), //  9 - green
36	    Color(0xFFF44336), // 10 - red
37	    Color(0xFF00E5FF), // 11 - cyan accent
38	    Color(0xFFCDDC39), // 12 - lime
39	  ];
40	
41	  Color _rankColor(int rank) {
42	    return _rankColors[(rank - 1) % _rankColors.length];
43	  }
44	
45	  @override
46	  void initState() {
47	    super.initState();
48	    _loadLikes();
49	  }
50	
51	  Future<String?> _getToken() async {
52	    final prefs = await SharedPreferences.getInstance();
53	    return prefs.getString('jwt_token');
54	  }
55	
56	  Future<void> _loadLikes() async {
57	    setState(() { _isLoading = true; _error = null; });
58	    try {
59	      final token = await _getToken();
60	      final response = await http.get(
61	        Uri.parse('$_baseUrl/api/who_i_like'),
62	        headers: {'Authorization': 'Bearer $token'},
63	      );
64	      if (response.statusCode == 200) {
65	        final data = jsonDecode(response.body) as Map<String, dynamic>;
66	        setState(() {
67	          _likes = (data['users'] as List<dynamic>).cast<Map<String, dynamic>>();
68	          _isLoading = false;
69	        });
70	      } else {
71	        setState(() { _error = 'Failed (${response.statusCode})'; _isLoading = false; });
72	      }
73	    } catch (e) {
74	      setState(() { _error = 'Error: $e'; _isLoading = false; });
75	    }
76	  }
77	
78	  Future<void> _pushRerank() async {
79	    try {
80	      final token = await _getToken();
81	      final rankings = _likes.asMap().entries.map((e) {
82	        return {'username': e.value['username'], 'rank': e.key + 1};
83	      }).toList();
84	      await http.put(
85	        Uri.parse('$_baseUrl/api/like/rerank'),
86	        headers: {'Authorization': 'Bearer $token', 'Content-Type': 'application/json'},
87	        body: jsonEncode({'rankings': rankings}),
88	      );
89	    } catch (_) {}
90	  }
91	
92	  @override
93	  Widget build(BuildContext context) {
94	    return Scaffold(
95	      backgroundColor: _bg,
96	      appBar: AppBar(
97	        backgroundColor: _bg,
98	        elevation: 0,
99	        centerTitle: true,
100	        title: const Column(
101	          children: [
102	            Text(
103	              'WHO I LIKE',
104	              style: TextStyle(
105	                color: Colors.white,
106	                fontWeight: FontWeight.bold,
107	                fontSize: 16,
108	                letterSpacing: 1.2,
109	              ),
110	            ),
111	            Text(
112	              'Slide up to prioritise your likes',
113	              style: TextStyle(color: Colors.white38, fontSize: 11),
114	            ),
115	          ],
116	        ),
117	        actions: [
118	          IconButton(
119	            icon: const Icon(Icons.refresh, color: Colors.white54),
120	            onPressed: _loadLikes,
121	          ),
122	        ],
123	      ),
124	      body: _buildBody(),
125	    );
126	  }
127	
128	  Widget _buildBody() {
129	    if (_isLoading) {
130	      return const Center(child: CircularProgressIndicator(color: Color(0xFFFFC107)));
131	    }
132	    if (_error != null) {
133	      return Center(child: Text(_error!, style: const TextStyle(color: Colors.redAccent)));
134	    }
135	    if (_likes.isEmpty) {
136	      return RefreshIndicator(
137	        onRefresh: _loadLikes,
138	        color: const Color(0xFFFFC107),
139	        child: ListView(children: [
140	          const SizedBox(height: 200),
141	          Center(
142	            child: Column(children: [
143	              const Icon(Icons.favorite_border, size: 64, color: Color(0xFFFFC107)),
144	              const SizedBox(height: 16),
145	              const Text('No likes yet', style: TextStyle(color: Colors.white70, fontSize: 16)),
146	              const SizedBox(height: 24),
147	              ElevatedButton(
148	                onPressed: () => widget.onSwitchTab(0),
149	                style: ElevatedButton.styleFrom(backgroundColor: const Color(0xFFFFC107), foregroundColor: Colors.black),
150	                child: const Text('Go to Search'),
151	              ),
152	            ]),
153	          ),
154	        ]),
155	      );
156	    }
157	
158	    return RefreshIndicator(
159	      onRefresh: _loadLikes,
160	      color: const Color(0xFFFFC107),
161	      child: ReorderableListView.builder(
162	        padding: const EdgeInsets.only(top: 8, bottom: 80),
163	        itemCount: _likes.length,
164	        onReorder: (oldIndex, newIndex) {
165	          setState(() {
166	            if (newIndex > oldIndex) newIndex--;
167	            final item = _likes.removeAt(oldIndex);
168	            _likes.insert(newIndex, item);
169	          });
170	          _pushRerank();
171	        },
172	        itemBuilder: (context, index) {
173	          final user = _likes[index];
174	          final rank = index + 1;
175	          final int userId = user['id'] as int? ?? 0;
176	          final String username = user['username'] as String? ?? '';
177	          final int? age = user['age'] as int?;
178	          final String? sex = user['sex'] as String?;
179	          final String photoUrl = '$_baseUrl/api/users/$userId/photo';
180	
181	          return _WhoILikeTile(
182	            key: ValueKey(userId),
183	            rank: rank,
184	            index: index,
185	            userId: userId,
186	            username: username,
187	            age: age,
188	            sex: sex,
189	            photoUrl: photoUrl,
190	            rankColor: _rankColor(rank),
191	            onTap: () => Navigator.push(
192	              context,
193	              MaterialPageRoute(builder: (_) => ProfileScreen(
194	                userId: userId, username: username,
195	                age: age ?? 0, sex: sex ?? '', photoUrl: photoUrl,
196	              )),
197	            ),
198	          );
199	        },
200	      ),
201	    );
202	  }
203	}
