1	import 'dart:async';
2	import 'dart:convert';
3	import 'package:flutter/material.dart';
4	import 'package:shared_preferences/shared_preferences.dart';
5	import 'package:web_socket_channel/web_socket_channel.dart';
6	import 'package:http/http.dart' as http;
7	import 'package:flutter_slidable/flutter_slidable.dart';
8	
9	const _baseUrl = 'http://10.0.2.2:8000';
10	const _wsUrl = 'ws://10.0.2.2:8000';
11	
12	class _WhoLikesMeEntry {
13	  final int id;
14	  final String username;
15	  final int? age;
16	  final String? sex;
17	  final String? photoUrl;
18	  int? myRankToThem;
19	
20	  _WhoLikesMeEntry({
21	    required this.id,
22	    required this.username,
23	    this.age,
24	    this.sex,
25	    this.photoUrl,
26	    this.myRankToThem,
27	  });
28	
29	  factory _WhoLikesMeEntry.fromJson(Map<String, dynamic> json) {
30	    return _WhoLikesMeEntry(
31	      id: json['id'] as int,
32	      username: json['username'] as String,
33	      age: json['age'] as int?,
34	      sex: json['sex'] as String?,
35	      photoUrl: json['photo_url'] as String?,
36	      myRankToThem: json['my_rank_to_them'] as int?,
37	    );
38	  }
39	}
40	
41	class WhoLikesMeScreen extends StatefulWidget {
42	  const WhoLikesMeScreen({super.key});
43	
44	  @override
45	  State<WhoLikesMeScreen> createState() => _WhoLikesMeScreenState();
46	}
47	
48	class _WhoLikesMeScreenState extends State<WhoLikesMeScreen> {
49	  List<_WhoLikesMeEntry> _entries = [];
50	  bool _loading = true;
51	  String? _error;
52	  final Set<int> _likedBack = {};
53	
54	  WebSocketChannel? _wsChannel;
55	  StreamSubscription? _wsSub;
56	  int? _currentUserId;
57	
58	  // Datetris rank colours
59	  static const _rankColors = [
60	    Color(0xFFFFC107), // 1 - amber
61	    Color(0xFFFF9800), // 2 - orange
62	    Color(0xFFE91E8C), // 3 - pink
63	    Color(0xFF9E9E9E), // 4+
64	  ];
65	
66	  Color _rankColor(int? rank) {
67	    if (rank == null) return const Color(0xFF9E9E9E);
68	    if (rank <= 3) return _rankColors[rank - 1];
69	    return _rankColors[3];
70	  }
71	
72	  @override
73	  void initState() {
74	    super.initState();
75	    _init();
76	  }
77	
78	  Future<void> _init() async {
79	    await _fetchData();
80	    await _connectWebSocket();
81	  }
82	
83	  Future<String?> _getToken() async {
84	    final prefs = await SharedPreferences.getInstance();
85	    return prefs.getString('jwt_token');
86	  }
87	
88	  Future<void> _fetchData() async {
89	    try {
90	      final token = await _getToken();
91	      if (token == null) {
92	        setState(() { _error = 'Not logged in'; _loading = false; });
93	        return;
94	      }
95	
96	      final meRes = await http.get(
97	        Uri.parse('$_baseUrl/api/users/me'),
98	        headers: {'Authorization': 'Bearer $token'},
99	      );
100	      if (meRes.statusCode == 200) {
101	        _currentUserId = (json.decode(meRes.body))['id'] as int?;
102	      }
103	
104	      final res = await http.get(
105	        Uri.parse('$_baseUrl/api/who_likes_me'),
106	        headers: {'Authorization': 'Bearer $token'},
107	      );
108	
109	      if (res.statusCode == 200) {
110	        final data = json.decode(res.body);
111	        final List<dynamic> users = data['users'] ?? [];
112	        setState(() {
113	          _entries = users.map((u) => _WhoLikesMeEntry.fromJson(u as Map<String, dynamic>)).toList();
114	          _loading = false;
115	        });
116	      } else {
117	        setState(() { _error = 'Failed (${res.statusCode})'; _loading = false; });
118	      }
119	    } catch (e) {
120	      setState(() { _error = 'Error: $e'; _loading = false; });
121	    }
122	  }
123	
124	  Future<void> _connectWebSocket() async {
125	    if (_currentUserId == null) return;
126	    final token = await _getToken();
127	    if (token == null) return;
128	    try {
129	      final uri = Uri.parse('$_wsUrl/api/ws/rank_updates/$_currentUserId');
130	      _wsChannel = WebSocketChannel.connect(uri);
131	      _wsSub = _wsChannel!.stream.listen(
132	        (message) => _handleWsMessage(message as String),
133	        onError: (e) => debugPrint('[WhoLikesMe WS] error: $e'),
134	        onDone: () => debugPrint('[WhoLikesMe WS] closed'),
135	      );
136	      debugPrint('[WhoLikesMe WS] connected for user $_currentUserId');
137	    } catch (e) {
138	      debugPrint('[WhoLikesMe WS] connect failed: $e');
139	    }
140	  }
141	
142	  void _handleWsMessage(String raw) {
143	    try {
144	      final data = json.decode(raw) as Map<String, dynamic>;
145	      if (data['type'] == 'rank_update') {
146	        final fromUsername = data['from_username'] as String?;
147	        final newRank = data['new_rank'] as int?;
148	        if (fromUsername == null || newRank == null) return;
149	        setState(() {
150	          final idx = _entries.indexWhere((e) => e.username == fromUsername);
151	          if (idx != -1) _entries[idx].myRankToThem = newRank;
152	        });
153	      }
154	    } catch (_) {}
155	  }
156	
157	  Future<void> _deleteLike(_WhoLikesMeEntry entry) async {
158	    setState(() => _entries.removeWhere((e) => e.id == entry.id));
159	    final token = await _getToken();
160	    if (token == null) return;
161	    try {
162	      await http.delete(
163	        Uri.parse('$_baseUrl/api/like/${entry.id}'),
164	        headers: {'Authorization': 'Bearer $token'},
165	      );
166	      if (mounted) {
167	        ScaffoldMessenger.of(context).showSnackBar(
168	          const SnackBar(content: Text('Removed')),
169	        );
170	      }
171	    } catch (e) {
172	      debugPrint('[WhoLikesMe] deleteLike error: $e');
173	    }
174	  }
175	
176	  Future<void> _blockUser(_WhoLikesMeEntry entry) async {
177	    setState(() => _entries.removeWhere((e) => e.id == entry.id));
178	    final token = await _getToken();
179	    if (token == null) return;
180	    try {
181	      await http.post(
182	        Uri.parse('$_baseUrl/api/block'),
183	        headers: {
184	          'Authorization': 'Bearer $token',
185	          'Content-Type': 'application/json',
186	        },
187	        body: json.encode({'blocked_user_id': entry.id}),
188	      );
189	    } catch (e) {
190	      debugPrint('[WhoLikesMe] blockUser error: $e');
191	    }
192	  }
193	
194	  Future<void> _likeBack(_WhoLikesMeEntry entry) async {
195	    final token = await _getToken();
196	    if (token == null) return;
197	    try {
198	      final res = await http.post(
199	        Uri.parse('$_baseUrl/api/like'),
200	        headers: {
201	          'Authorization': 'Bearer $token',
202	          'Content-Type': 'application/json',
203	        },
204	        body: json.encode({'liked_user_id': entry.id}),
205	      );
206	      if (res.statusCode == 200) {
207	        final data = json.decode(res.body) as Map<String, dynamic>;
208	        final status = data['status'] as String?;
209	        if (status == 'matched') {
210	          setState(() => _entries.removeWhere((e) => e.id == entry.id));
211	          if (mounted) {
212	            ScaffoldMessenger.of(context).showSnackBar(
213	              const SnackBar(content: Text('🎉 It\'s a match!')),
214	            );
215	          }
216	        } else {
217	          setState(() => _likedBack.add(entry.id));
218	          if (mounted) {
219	            ScaffoldMessenger.of(context).showSnackBar(
220	              const SnackBar(content: Text('❤️ Like sent!')),
221	            );
222	          }
223	        }
224	      } else {
225	        final body = res.body;
226	        if (mounted) {
227	          ScaffoldMessenger.of(context).showSnackBar(
228	            SnackBar(content: Text('Error ${res.statusCode}: $body')),
229	          );
230	        }
231	      }
232	    } catch (e) {
233	      if (mounted) {
234	        ScaffoldMessenger.of(context).showSnackBar(
235	          SnackBar(content: Text('Error: $e')),
236	        );
237	      }
238	    }
239	  }
240	
241	  @override
242	  void dispose() {
243	    _wsSub?.cancel();
244	    _wsChannel?.sink.close();
245	    super.dispose();
246	  }
247	
248	  @override
249	  Widget build(BuildContext context) {
250	    return Scaffold(
251	      backgroundColor: const Color(0xFF0E0E0E),
252	      appBar: AppBar(
253	        backgroundColor: const Color(0xFF0E0E0E),
254	        elevation: 0,
255	        centerTitle: true,
256	        title: const Column(
257	          children: [
258	            Text(
259	              'WHO LIKES ME',
260	              style: TextStyle(
261	                color: Colors.white,
262	                fontWeight: FontWeight.bold,
263	                fontSize: 16,
264	                letterSpacing: 1.2,
265	              ),
266	            ),
267	            Text(
268	              'Swipe left to remove · Swipe right to block',
269	              style: TextStyle(color: Colors.white38, fontSize: 11),
270	            ),
271	          ],
272	        ),
273	      ),
274	      body: _buildBody(),
275	    );
276	  }
277	
278	  Widget _buildBody() {
279	    if (_loading) {
280	      return const Center(child: CircularProgressIndicator(color: Color(0xFFFFC107)));
281	    }
282	    if (_error != null) {
283	      return Center(child: Text(_error!, style: const TextStyle(color: Colors.redAccent)));
284	    }
285	    if (_entries.isEmpty) {
286	      return RefreshIndicator(
287	        onRefresh: _fetchData,
288	        color: const Color(0xFFFFC107),
289	        child: ListView(children: const [
290	          SizedBox(height: 200),
291	          Center(child: Column(children: [
292	            Icon(Icons.favorite_border, size: 64, color: Color(0xFFFFC107)),
293	            SizedBox(height: 16),
294	            Text('No one has liked you yet', style: TextStyle(color: Colors.white70, fontSize: 16)),
295	          ])),
296	        ]),
297	      );
298	    }
299	
300	    return RefreshIndicator(
301	      onRefresh: _fetchData,
302	      color: const Color(0xFFFFC107),
303	      child: ListView.builder(
304	        padding: const EdgeInsets.only(top: 8, bottom: 80),
305	        itemCount: _entries.length,
306	        itemBuilder: (context, index) => _buildTile(_entries[index]),
307	      ),
308	    );
309	  }
