311	  Widget _buildTile(_WhoLikesMeEntry entry) {
312	    final rank = entry.myRankToThem;
313	    final rankColor = _rankColor(rank);
314	    final photoUrl = entry.photoUrl?.replaceFirst('http://0.0.0.0:8000', _baseUrl)
315	        ?? '$_baseUrl/api/users/${entry.id}/photo';
316	
317	    return Slidable(
318	      key: ValueKey(entry.id),
319	      startActionPane: ActionPane(
320	        motion: const BehindMotion(),
321	        extentRatio: 0.25,
322	        children: [
323	          SlidableAction(
324	            onPressed: (_) => _blockUser(entry),
325	            backgroundColor: const Color(0xFFFF9800),
326	            foregroundColor: Colors.white,
327	            icon: Icons.block,
328	            label: 'Block',
329	            borderRadius: BorderRadius.circular(8),
330	          ),
331	        ],
332	      ),
333	      endActionPane: ActionPane(
334	        motion: const BehindMotion(),
335	        extentRatio: 0.25,
336	        children: [
337	          SlidableAction(
338	            onPressed: (_) => _deleteLike(entry),
339	            backgroundColor: Colors.redAccent,
340	            foregroundColor: Colors.white,
341	            icon: Icons.delete_outline,
342	            label: 'Remove',
343	            borderRadius: BorderRadius.circular(8),
344	          ),
345	        ],
346	      ),
347	      child: Column(
348	        children: [
349	          Padding(
350	            padding: const EdgeInsets.symmetric(horizontal: 16, vertical: 14),
351	            child: Row(
352	              children: [
353	                // Rank number
354	                SizedBox(
355	                  width: 40,
356	                  child: Text(
357	                    rank != null ? '$rank' : '—',
358	                    style: TextStyle(
359	                      color: rankColor,
360	                      fontSize: 28,
361	                      fontWeight: FontWeight.bold,
362	                    ),
363	                  ),
364	                ),
365	                // Dot indicators (age/sex badges)
366	                Column(
